INSERT INTO `edu_news` VALUES ('30', '关于2026年春季学期期中教学检查的通知', '教务处将于第8-9周组织开展春季学期期中教学检查工作，重点检查课堂教学质量、实践教学环节和教学档案管理情况。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各教学单位：</p><p>为进一步规范教学管理，全面了解本学期教学运行状况，及时发现和解决教学过程中存在的问题，根据学校教学工作安排，决定于第8-9周（4月20日-4月30日）开展2026年春季学期期中教学检查工作。现将有关事项通知如下：</p><p>一、检查内容：课堂教学质量（包括教师到岗、学生到课、课堂教学组织等）、实践教学环节（包括实验、实习、课程设计等）、教学档案管理（包括教学日历、教案、作业批改等）。</p><p>二、检查方式：采取学院自查与学校抽查相结合的方式进行。各学院于4月23日前完成自查并提交自查报告，学校检查组将于4月26-30日进行随机抽查。</p><p>三、工作要求：请各学院高度重视本次期中教学检查工作，认真组织，实事求是地查找问题，制定整改措施。</p>', '2026-04-18 08:30:00', '320', '1', '100', '0', '1', 'admin', '2026-04-18 08:30:00', '', '2026-04-18 08:30:00', '0');
INSERT INTO `edu_news` VALUES ('31', '关于开展教师教学能力提升培训的通知', '教务处将于5月举办\"教学创新与信息化教学能力提升\"系列培训，邀请校内外专家开展专题讲座和工作坊。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各位教师：</p><p>为持续提升我校教师教学能力和专业素养，推动信息技术与教育教学深度融合，教务处拟于2026年5月举办\"教学创新与信息化教学能力提升\"系列培训活动。具体安排如下：</p><p>一、培训时间：2026年5月6日-5月27日，每周三、周五下午14:30-17:00。</p><p>二、培训内容：教学创新大赛经验分享、混合式教学设计工作坊、AI辅助教学工具使用培训、一流课程申报指导等。</p><p>三、培训对象：全校在职教师均可报名参加，鼓励中青年教师和新入职教师积极参加。</p><p>四、报名方式：请于4月30日前登录教师发展中心系统在线报名。</p>', '2026-04-22 10:00:00', '185', '1', '100', '0', '1', 'admin', '2026-04-22 10:00:00', '', '2026-04-22 10:00:00', '0');
INSERT INTO `edu_news` VALUES ('32', '关于提交省级教学成果奖申报材料的紧急通知', '请各学院于4月28日下班前将2026年度省级教学成果奖申报材料报送至教务处教学研究科，逾期不予受理。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院：</p><p>根据河南省教育厅《关于开展2026年度河南省高等教育省级教学成果奖评选工作的通知》要求，学校现组织省级教学成果奖申报推荐工作。有关事项紧急通知如下：</p><p>一、申报范围：已获得2024-2025学年校级教学成果一等奖及以上的成果。</p><p>二、申报材料：（1）《河南省高等教育省级教学成果奖申报书》（一式三份）；（2）成果总结报告（不超过5000字）；（3）支撑材料（含成果应用效果证明、公开发表的论文等）。</p><p>三、时间节点：请各学院于4月28日（周二）17:00前将申报材料电子版和纸质版报送至教务处教学研究科（办公楼302室）。逾期不予受理，请务必按时提交。</p><p>联系人：张老师，电话：0371-8660XXXX</p>', '2026-04-25 15:00:00', '474', '1', '100', '0', '1', 'admin', '2026-04-25 15:00:00', '', '2026-04-25 15:00:00', '0');
INSERT INTO `edu_news` VALUES ('33', '2026届毕业设计中期检查工作安排', '教务处将于5月上旬对2026届本科毕业设计（论文）工作进行中期检查，重点检查指导教师履职和进展情况。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院：</p><p>为加强本科毕业设计（论文）过程管理，确保毕业设计工作质量，根据《郑州轻工业大学本科毕业设计（论文）管理办法》，决定对2026届本科毕业设计（论文）进行中期检查。具体安排如下：</p><p>一、检查时间：2026年5月6日-5月15日。</p><p>二、检查内容：指导教师履职情况、学生毕业设计（论文）进展、开题报告质量、外文翻译完成情况等。</p><p>三、检查方式：各学院成立中期检查小组，采取学生汇报、查阅材料、座谈交流等方式开展检查。学校将组织专家组进行抽查。</p><p>四、材料报送：各学院于5月18日前将中期检查总结报告报送教务处实践教学科。</p>', '2026-04-24 09:00:00', '256', '1', '100', '0', '1', 'admin', '2026-04-24 09:00:00', '', '2026-04-24 09:00:00', '0');
INSERT INTO `edu_news` VALUES ('34', '关于推荐优秀教学成果参加全国展示的通知', '教育部将于6月举办全国高校教学成果展，现面向全校征集优秀教学成果参展项目，请各单位积极推荐。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各单位：</p><p>根据教育部高等教育司通知，2026年度全国高校教学成果展定于6月15-17日在北京国家会议中心举办。为充分展示我校教育教学改革成果，现面向全校征集参展项目。具体要求如下：</p><p>一、征集范围：近三年获得校级及以上教学成果奖的项目，或在教学改革中取得突出成效的成果。</p><p>二、推荐名额：每个学院可推荐1-2项优秀成果。</p><p>三、参展形式：实物展板、视频展示、互动演示等。</p><p>四、时间安排：请各学院于5月10日前将推荐项目汇总表及展示材料初稿提交至教务处。</p>', '2026-04-20 14:00:00', '198', '1', '100', '0', '1', 'admin', '2026-04-20 14:00:00', '', '2026-04-20 14:00:00', '0');
INSERT INTO `edu_news` VALUES ('35', '关于2026年度校级教学成果奖申报工作的通知', '2026年度校级教学成果奖申报工作即日启动，请各单位组织教师按时通过教学成果管理平台在线提交材料。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各单位：</p><p>根据学校工作安排，2026年度校级教学成果奖申报工作即日启动。现将有关事项通知如下：</p><p>一、申报范围：全校在职教师及教学管理人员，申报成果应为近4年（2022年9月至2026年4月）取得的教学成果。</p><p>二、申报时间：即日起至2026年5月31日。</p><p>三、申报方式：登录教学成果管理平台，在线填写申报信息并上传相关证明材料。</p><p>四、奖项设置：设特等奖、一等奖、二等奖三个等级，获奖成果将择优推荐申报省级教学成果奖。</p>', '2026-04-15 08:00:00', '385', '1', '100', '0', '1', 'admin', '2026-04-15 08:00:00', '', '2026-04-15 08:00:00', '0');
INSERT INTO `edu_news` VALUES ('36', '关于调整教学成果校级审核评分细则的通知', '为进一步规范教学成果审核流程，教务处对校级审核评分标准进行了优化调整，增加了创新性权重和推广应用效果维度。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院及校级审核员：</p><p>为提升教学成果审核的规范性与公正性，教务处在广泛征求意见的基础上，对校级审核评分细则进行了以下优化调整：</p><p>一、调整创新性权重，由原15%提升至25%，鼓励教师在教学理念、教学模式、教学方法等方面进行原创性探索。</p><p>二、新增\"推广应用效果\"评估维度（权重15%），考察成果在校内外推广应用的范围和实际效果。</p><p>三、细化教学改革类成果的评价指标，增设\"理论支撑\"、\"方案设计\"、\"实施过程\"、\"效果评价\"四个二级指标。</p><p>四、新评分细则自2026年5月1日起施行，届时教学成果管理平台将同步更新评分模板。</p>', '2026-04-12 10:00:00', '310', '1', '100', '0', '1', 'admin', '2026-04-12 10:00:00', '', '2026-04-12 10:00:00', '0');
INSERT INTO `edu_news` VALUES ('37', '关于2026年度教学改革研究项目立项申报的通知', '学校启动2026年度校级教学改革研究项目立项申报工作，设重点项目和一般项目两个类别。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各单位：</p><p>为深化教育教学改革，鼓励教师积极开展教学研究，学校决定开展2026年度校级教学改革研究项目立项申报工作。有关事项通知如下：</p><p>一、项目类别：设重点项目（资助3万元/项）和一般项目（资助1万元/项）。</p><p>二、申报方向：课程思政建设、一流课程建设、实践教学改革、创新创业教育、教学质量保障等。</p><p>三、申报条件：项目负责人须具有中级及以上职称，原则上在研校级教改项目不超过1项。</p><p>四、申报截止时间：2026年5月20日。</p>', '2026-04-08 09:00:00', '278', '1', '100', '0', '1', 'admin', '2026-04-08 09:00:00', '', '2026-04-08 09:00:00', '0');
INSERT INTO `edu_news` VALUES ('38', '关于公布2025-2026学年第二学期教学督导工作安排的通知', '学校教学督导委员会发布了本学期教学督导工作计划，将开展常规听课评课和专项教学质量检查。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各教学单位：</p><p>为加强教学质量监控，促进教师教学能力提升，学校教学督导委员会制定了2025-2026学年第二学期教学督导工作计划。现将有关安排公布如下：</p><p>一、常规听课评课：校级督导专家本学期计划听课评课不少于60节次，覆盖各学院青年教师和新开课程。</p><p>二、专项检查：重点开展\"混合式教学实施情况\"和\"课程思政建设情况\"两项专项检查。</p><p>三、教学沙龙：每月举办1次教学沙龙活动，邀请优秀教师分享教学经验。</p><p>四、反馈机制：督导意见将通过教务系统及时反馈给教师本人和所在学院。</p>', '2026-03-25 14:00:00', '145', '1', '100', '0', '1', 'admin', '2026-03-25 14:00:00', '', '2026-03-25 14:00:00', '0');
INSERT INTO `edu_news` VALUES ('39', '关于教学成果管理平台使用培训的通知', '教务处将于4月举办两场教学成果管理平台操作培训，帮助教师熟练使用平台进行成果申报和审核。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>各学院、各位教师：</p><p>为帮助各位教师和审核人员熟练掌握新版教学成果管理平台的操作，教务处拟举办两场线上培训。具体安排如下：</p><p>一、第一场（教师专场）：4月28日（周二）14:30-16:00，培训内容：成果申报、材料上传、进度查询、驳回修改等操作。</p><p>二、第二场（审核员专场）：4月29日（周三）14:30-16:00，培训内容：审核流程操作、评分表填写、审核意见撰写规范。</p><p>三、培训方式：通过腾讯会议线上进行（会议号另行通知），同时录制视频上传至平台供回看。</p><p>四、参加人员：请各学院教学秘书、拟申报成果的教师及相关审核人员务必参加。</p>', '2026-04-25 09:00:00', '110', '1', '100', '0', '1', 'admin', '2026-04-25 09:00:00', '', '2026-04-25 09:00:00', '0');
INSERT INTO `edu_news` VALUES ('40', '我校成功举办2026年教学创新大赛', '4月20日，郑州轻工业大学2026年教学创新大赛决赛在科学校区学术报告厅举行，来自各学院的18位教师参加了决赛展示。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>4月20日，郑州轻工业大学2026年教学创新大赛决赛在科学校区学术报告厅隆重举行。本次大赛以\"创新教学、提质增效\"为主题，经各学院初赛推荐，共有18位教师进入校级决赛。</p><p>比赛分为教学设计汇报和现场授课展示两个环节。参赛教师围绕课程思政融入、混合式教学设计、项目驱动教学、虚拟仿真实验等主题进行了精彩展示，充分体现了我校教师在教学改革与创新方面的积极探索。</p><p>经评委评审，软件学院张伟老师、外国语学院孙悦老师荣获一等奖；另有3位教师获二等奖，5位教师获三等奖。校领导为获奖教师颁奖，并鼓励全体教师以赛促教、以赛促改，不断提升教学水平。</p>', '2026-04-21 16:00:00', '432', '1', '90', '0', '2', 'admin', '2026-04-21 16:00:00', '', '2026-04-21 16:00:00', '0');
INSERT INTO `edu_news` VALUES ('41', '计算机学院获批国家一流本科专业建设点', '我校计算机科学与技术专业成功入选2025年度国家级一流本科专业建设点，标志着我校计算机类专业建设迈上新台阶。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>近日，教育部办公厅公布了2025年度国家级一流本科专业建设点名单，我校计算机科学与技术专业成功入选。这是继食品科学与工程、高分子材料与工程之后，我校获批的第三个国家级一流本科专业建设点。</p><p>计算机科学与技术专业始建于1994年，经过三十余年的建设发展，已经形成了较为完善的\"基础理论+工程实践+创新训练\"人才培养体系。该专业近年来在课程建设、教材建设、实验室建设等方面取得了显著成绩，学生在ACM程序设计竞赛、中国大学生计算机设计大赛等赛事中屡获佳绩。</p><p>学院负责人表示，将以国家级一流专业建设为契机，进一步深化教育教学改革，努力培养更多高素质计算机专业人才。</p>', '2026-03-20 10:00:00', '486', '1', '85', '0', '2', 'admin', '2026-03-20 10:00:00', '', '2026-03-20 10:00:00', '0');
INSERT INTO `edu_news` VALUES ('42', '软件学院校企合作成果入选教育部典型案例', '我校软件学院与中软国际联合建设的\"产教融合软件人才培养基地\"成功入选教育部2025年产教融合校企合作典型案例。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>近日，教育部高等教育司公布了2025年度产教融合校企合作典型案例名单，我校软件学院与中软国际联合建设的\"产教融合软件人才培养基地\"成功入选，全国共有100个案例获此殊荣。</p><p>该基地自2023年启动建设以来，校企双方在人才培养方案制定、课程资源开发、双师型教师培养、学生实习实训等方面开展了全方位合作。已联合开发校企合作课程12门，共建实验室3个，企业工程师进校授课累计超过1000学时。三年来，基地累计培养软件工程专业学生600余名，毕业生一次就业率保持在94%以上。</p><p>软件学院院长表示，此次入选教育部典型案例是对学校产教融合工作的充分肯定，学院将继续深化校企合作内涵，探索更多产教融合新模式。</p>', '2026-03-05 09:00:00', '295', '1', '80', '0', '2', 'admin', '2026-03-05 09:00:00', '', '2026-03-05 09:00:00', '0');
INSERT INTO `edu_news` VALUES ('43', '我校教师在省级教学竞赛中荣获一等奖', '在2026年河南省本科高校教师课堂教学创新大赛中，我校电气信息工程学院周鹏老师荣获理工组一等奖。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>近日，由河南省教育厅主办的2026年河南省本科高校教师课堂教学创新大赛圆满落幕。经过激烈角逐，我校电气信息工程学院周鹏老师凭借\"电力系统分析\"课程精彩的课堂展示和创新的教学设计，荣获理工组一等奖；外国语学院孙悦老师获文科组二等奖。</p><p>本次大赛共有来自全省56所本科高校的180余名教师参赛。周鹏老师在比赛中展示了其独创的\"工程案例导入+仿真软件辅助+小组探究研讨\"三段式教学模式，将抽象的电力系统概念通过工程实例和仿真可视化生动呈现。</p><p>教务处负责人表示，学校将以此次获奖为契机，进一步推动课堂教学改革，鼓励更多教师投身教学创新实践。</p>', '2026-04-03 15:00:00', '378', '1', '75', '0', '2', 'admin', '2026-04-03 15:00:00', '', '2026-04-03 15:00:00', '0');
INSERT INTO `edu_news` VALUES ('44', '外国语学院探索\"AI+外语\"教学新模式', '外国语学院举办\"AI赋能外语教学\"专题研讨会，探讨人工智能技术在语言教学中的创新应用路径。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>4月16日，外国语学院在东风校区语言实验中心举办了\"AI赋能外语教学\"专题研讨会。来自省内外8所高校的60余名外语教师参加了本次研讨。</p><p>研讨会围绕\"大语言模型辅助外语写作教学\"、\"AI口语陪练系统的课堂应用\"、\"个性化外语学习路径智能推荐\"等前沿话题展开深入交流。会议邀请了北京外国语大学梁茂成教授作题为\"人工智能时代的外语教育变革\"的主旨报告。本校外国语学院马超教授分享了\"基于AI技术的外语写作智能反馈系统\"的研发与应用经验。</p><p>外国语学院院长在总结中表示，学院将以此次研讨会为新起点，加快推动AI技术与外语教学的深度融合，探索\"AI+外语\"教学新模式。</p>', '2026-04-17 14:00:00', '221', '1', '70', '0', '2', 'admin', '2026-04-17 14:00:00', '', '2026-04-17 14:00:00', '0');
INSERT INTO `edu_news` VALUES ('45', '我校获批4项省级教学改革研究重点项目', '省教育厅公布了2026年度省级教学改革研究项目立项名单，我校4个项目获批为重点项目，资助经费总额达80万元。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>近日，河南省教育厅公布了2026年度省级教学改革研究项目立项名单，我校共有4个项目获批为重点项目，涵盖课程思政建设、实践教学体系改革、创新创业教育模式探索、教学质量保障机制优化四大领域，资助经费总额达80万元。</p><p>获批项目分别为：软件学院张伟副教授主持的\"新工科视域下软件工程专业课程思政教学改革与实践\"、电气信息工程学院郑丽教授主持的\"基于OBE理念的自动化专业实践教学体系重构\"、经济与管理学院杨帆副教授主持的\"大数据驱动的经管类创新创业教育模式研究\"、教务处主持的\"地方高校教学质量保障体系优化研究\"。</p><p>学校将以此次省级教改项目立项为契机，持续深化教育教学改革，高质量推进一流本科教育建设。</p>', '2026-04-10 08:30:00', '340', '1', '85', '0', '2', 'admin', '2026-04-10 08:30:00', '', '2026-04-10 08:30:00', '0');
INSERT INTO `edu_news` VALUES ('46', '数学学院在全国大学生数学建模竞赛中再创佳绩', '2025年\"高教社杯\"全国大学生数学建模竞赛成绩揭晓，我校代表队获国家级一等奖3项、二等奖6项。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>日前，2025年\"高教社杯\"全国大学生数学建模竞赛获奖名单正式公布。我校选派的30支参赛队伍中，共有24支队伍获奖，获奖率高达80%。其中，国家级一等奖3项、二等奖6项，省级一等奖8项、二等奖7项，获奖数量和质量均创历史新高。</p><p>全国大学生数学建模竞赛是由中国工业与应用数学学会主办的面向全国大学生的群众性科技活动，是首批列入\"高校学科竞赛排行榜\"的19项竞赛之一。2025年全国共有来自1600余所院校的5万余支队伍参赛。</p><p>数学与信息科学学院负责人表示，优异成绩的取得离不开指导教师的辛勤付出和学生的刻苦钻研，学院将继续以学科竞赛为牵引，推动数学教学改革和人才培养质量提升。</p>', '2026-03-15 10:00:00', '455', '1', '80', '0', '2', 'admin', '2026-03-15 10:00:00', '', '2026-03-15 10:00:00', '0');
INSERT INTO `edu_news` VALUES ('47', '经济与管理学院举办\"数字经济时代的管理教育\"论坛', '4月8日，经济与管理学院举办学术论坛，探讨数字经济背景下管理学科教育改革的新理念、新路径。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>4月8日，经济与管理学院在科学校区学术交流中心举办了\"数字经济时代的管理教育\"主题论坛。论坛邀请了中国人民大学、西安交通大学等高校的5位知名管理学者作学术报告。</p><p>论坛围绕\"数字经济对管理教育的影响与挑战\"、\"大数据与AI在管理课程中的整合\"、\"新商科人才培养模式的转型\"等议题进行了深入研讨。与会专家一致认为，数字经济时代的管理教育必须加快数字化转型，培养学生的数据思维、平台思维和创新思维。</p><p>经济与管理学院院长表示，学院将以此次论坛成果为指导，加快推进管理类课程的数字化转型，努力培养适应数字经济发展需求的高素质管理人才。</p>', '2026-04-09 11:00:00', '168', '1', '60', '0', '2', 'admin', '2026-04-09 11:00:00', '', '2026-04-09 11:00:00', '0');
INSERT INTO `edu_news` VALUES ('48', '学校召开2026年本科教学工作推进会', '3月25日，学校召开本科教学工作推进会，部署2026年本科教学重点工作，强调以审核评估为契机全面提升教学质量。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>3月25日上午，郑州轻工业大学2026年本科教学工作推进会在科学校区办公楼第一会议室召开。校长出席会议并讲话，各学院院长、教学副院长、教务处全体人员参加会议。</p><p>会议部署了2026年本科教学八项重点工作：一是高质量推进一流专业和一流课程建设；二是深化课程思政教学改革；三是加强实践教学体系建设；四是做好本科教育教学审核评估迎评工作；五是推进教师教学能力提升工程；六是完善教学质量保障体系；七是深化产教融合协同育人；八是加快教育数字化转型。</p><p>校长在讲话中强调，各学院要以审核评估为契机，以评促建、以评促改，不断提升本科教育教学质量，为学校建设高水平轻工业大学贡献力量。</p>', '2026-03-26 09:00:00', '503', '1', '90', '0', '2', 'admin', '2026-03-26 09:00:00', '', '2026-03-26 09:00:00', '0');
INSERT INTO `edu_news` VALUES ('49', '教务处完成新版教学成果管理平台上线运行', '经过三个月的开发测试，新版教学成果管理平台已于近日正式上线，实现了成果申报、审核、统计的全流程在线管理。', 'http://127.0.0.1:9000/edu-achievement/2026/04/23/ccb7e2ddbe13b53276_20260423205208A002.jpg', '<p>经过近三个月的紧张开发和测试，新版教学成果管理平台已于近日正式上线运行。该平台基于Spring Cloud微服务架构开发，实现了教学成果从申报、审核、公示到统计的全流程在线管理。</p><p>新版平台在功能上有以下亮点：一是支持富文本编辑器，教师可在线撰写成果详细内容并上传多种格式附件；二是支持多级审核流程，涵盖了院级初审和校级终审两个环节；三是提供丰富的统计分析和数据可视化功能，可按学院、类型、等级等维度生成统计报表；四是优化了门户展示功能，审核通过的成果可自动推送到门户网站公开展示。</p><p>平台上线以来，已有超过50位教师使用平台提交了教学成果申报，整体运行稳定。教务处将继续收集用户反馈，持续优化平台功能。</p>', '2026-03-10 10:00:00', '275', '1', '75', '0', '2', 'admin', '2026-03-10 10:00:00', '', '2026-03-10 10:00:00', '0');
